import sys
import threading
from collections import deque

MOD = 998244353

def main():
    sys.setrecursionlimit(1 << 25)
    H, W = map(int, sys.stdin.readline().split())
    grid = [list(sys.stdin.readline().strip()) for _ in range(H)]

    visited = [[False] * W for _ in range(H)]
    components = []
    dirs = [(-1, 0), (1, 0), (0, -1), (0, 1)]

    comp_id = 0
    comp_map = {}  # (x, y) -> component id

    def bfs(i, j):
        q = deque()
        q.append((i, j))
        visited[i][j] = True
        comp = [(i, j)]
        while q:
            x, y = q.popleft()
            for dx, dy in dirs:
                nx, ny = x + dx, y + dy
                if 0 <= nx < H and 0 <= ny < W and not visited[nx][ny] and grid[nx][ny] == '#':
                    visited[nx][ny] = True
                    comp.append((nx, ny))
                    q.append((nx, ny))
        return comp

    num_components = 0
    for i in range(H):
        for j in range(W):
            if grid[i][j] == '#' and not visited[i][j]:
                comp = bfs(i, j)
                for (x, y) in comp:
                    comp_map[(x, y)] = comp_id
                comp_id += 1
                num_components += 1

    total = 0
    red_cells = 0

    def get_neighbors(x, y):
        res = set()
        for dx, dy in dirs:
            nx, ny = x + dx, y + dy
            if 0 <= nx < H and 0 <= ny < W:
                if grid[nx][ny] == '#':
                    res.add(comp_map[(nx, ny)])
        return res

    for i in range(H):
        for j in range(W):
            if grid[i][j] == '.':
                red_cells += 1
                neighbors = get_neighbors(i, j)
                unique_neighbors = len(set(neighbors))
                new_components = num_components - unique_neighbors + 1
                total += new_components

    if red_cells == 0:
        print(0)
        return

    def extended_gcd(a, b):
        if a == 0:
            return (b, 0, 1)
        else:
            g, y, x = extended_gcd(b % a, a)
            return (g, x - (b // a) * y, y)

    def modinv(a, mod):
        g, x, y = extended_gcd(a, mod)
        if g != 1:
            return None
        else:
            return x % mod

    inv_denominator = modinv(red_cells, MOD)
    result = (total * inv_denominator) % MOD
    print(result)

threading.Thread(target=main).start()
